 ('7848ed9d-732c-5f4d-8e60-0394d16063d2','b924b717-307c-581f-b5ef-3217bdbe0d37',4,$p$Concesión con verbo al final: hoewel, ofschoon$p$,$p$Concesión con verbo al final: hoewel, ofschoon$p$,'lesson',15),
 ('932dc654-483c-5fa2-9a66-d344a7e4abbd','b924b717-307c-581f-b5ef-3217bdbe0d37',5,$p$🏁 Checkpoint Eenheid 22$p$,$p$Demuestra que dominas los conectores avanzados del neerlandés formal: niettemin, desondanks, bovendien y daarentegen (que en posición inicial exigen inversión sujeto-verbo), hoewel y ofschoon (que envían el verbo al final de la subordinada), y los pares correlativos enerzijds…anderzijds, zowel…als, noch…noch. Elige el conector correcto y coloca el verbo en su sitio.$p$,'checkpoint',40)
