 ('986d3df9-98fb-5e00-bcd0-9bac0afdd2f2','20000000-0000-0000-0000-000000000006','checkpoint','B2','b924b717-307c-581f-b5ef-3217bdbe0d37',300,0.80,$j${"skills": ["reading", "listening", "writing", "speaking"], "item_count": 10, "randomize": true}$j$::jsonb) on conflict (id) do nothing;
insert into content_items (id, course_id, cefr_level, skill, type, prompt, payload, correct_answer, difficulty, tags) values
('971cad58-1a17-5162-9a6e-bf7463649737'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'B2','reading','match',$p$Une cada conector formal de contraste con su significado en español.$p$,$j${"pairs": [{"en": "niettemin", "es": "no obstante"}, {"en": "desondanks", "es": "a pesar de ello"}, {"en": "evenwel", "es": "sin embargo (formal)"}]}$j$::jsonb,$j${"pairs": [["niettemin", "no obstante"], ["desondanks", "a pesar de ello"], ["evenwel", "sin embargo (formal)"]]}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$contrast_adverbs$p$, $p$reading$p$]),
('1b2f171b-1f01-53a8-9bcf-0fc7592145e9'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'B2','reading','multiple_choice',$p$El plan salió mal. Elige la continuación con 'niettemin' e inversión correcta del verbo.$p$,$j${"options": ["Niettemin bleef het team optimistisch.", "Niettemin het team bleef optimistisch.", "Niettemin het bleef team optimistisch."]}$j$::jsonb,$j${"value": "Niettemin bleef het team optimistisch."}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$niettemin_inversion$p$, $p$reading$p$]),
('5f7f81b2-4d77-5029-9ea5-e50c16129f0d'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'B2','reading','multiple_choice',$p$Llovió todo el día. Elige la oración con 'desondanks' y el verbo en segunda posición.$p$,$j${"options": ["Desondanks gingen we naar het strand.", "Desondanks we gingen naar het strand.", "Desondanks naar het strand we gingen."]}$j$::jsonb,$j${"value": "Desondanks gingen we naar het strand."}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$desondanks_inversion$p$, $p$reading$p$]),
('90191320-b4a1-5e75-a1c1-ae8366ec3668'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'B2','reading','multiple_choice',$p$Se presentan dos caras de un asunto. Elige el par correlativo correcto ('por una parte… por otra parte').$p$,$j${"options": ["Enerzijds is het duur, anderzijds is het van hoge kwaliteit.", "Zowel is het duur, noch is het van hoge kwaliteit.", "Enerzijds is het duur, niettemin is het van hoge kwaliteit."]}$j$::jsonb,$j${"value": "Enerzijds is het duur, anderzijds is het van hoge kwaliteit."}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$enerzijds_anderzijds$p$, $p$reading$p$]),
('59bf5c80-ac6f-594e-ba17-1faaeb19ccb9'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'B2','reading','match',$p$Une cada expresión correlativa neerlandesa con su significado en español.$p$,$j${"pairs": [{"en": "zowel … als …", "es": "tanto… como…"}, {"en": "noch … noch …", "es": "ni… ni…"}, {"en": "enerzijds … anderzijds …", "es": "por una parte… por otra parte…"}]}$j$::jsonb,$j${"pairs": [["zowel … als …", "tanto… como…"], ["noch … noch …", "ni… ni…"], ["enerzijds … anderzijds …", "por una parte… por otra parte…"]]}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$noch_noch$p$, $p$reading$p$]),
('b6c5fbe6-663d-54b4-a8d6-be039c415792'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'B2','writing','cloze',$p$Completa con el adverbio de contraste (empieza con n). Fíjate en que el verbo 'blijft' va justo después.$p$,$j${"text": "Het is een lastig project. ___ blijft de directie er vertrouwen in houden."}$j$::jsonb,$j${"value": "Niettemin", "accepted": ["Niettemin", "niettemin"]}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$niettemin_cloze$p$, $p$writing$p$]),
('367ab000-3663-5643-92b5-b7ffc2c05c1c'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'B2','writing','translation',$p$Traduce al neerlandés formal usando 'evenwel' con inversión: 'Sin embargo, el resultado fue positivo.'$p$,$j${"source": "Sin embargo, el resultado fue positivo."}$j$::jsonb,$j${"value": "Evenwel was het resultaat positief.", "accepted": ["Evenwel was het resultaat positief.", "Evenwel was het resultaat positief", "Het resultaat was evenwel positief.", "Het resultaat was evenwel positief"]}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$evenwel_translation$p$, $p$writing$p$]),
('d380fe62-d680-5b93-b9c8-cf7d7954fa69'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'B2','writing','cloze',$p$Completa con el adverbio que expresa contraste ('en cambio', empieza con d). El verbo 'zijn' lo sigue.$p$,$j${"text": "Mijn broer houdt van de stad. ___ zijn wij liever op het platteland."}$j$::jsonb,$j${"value": "Daarentegen", "accepted": ["Daarentegen", "daarentegen"]}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$daarentegen_contrast$p$, $p$writing$p$]),
('e30b7756-6893-5be4-b903-7ac008a9901b'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'B2','writing','cloze',$p$Completa con el segundo elemento del par 'zowel … ___' (tanto… como).$p$,$j${"text": "Zowel de leraar ___ de leerlingen waren tevreden met het resultaat."}$j$::jsonb,$j${"value": "als", "accepted": ["als"]}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$zowel_als_cloze$p$, $p$writing$p$]),
('bc633de3-c355-51c6-9b91-2a3c714302e6'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'B2','writing','translation',$p$Traduce usando 'noch … noch …': 'No tengo ni tiempo ni dinero.'$p$,$j${"source": "No tengo ni tiempo ni dinero."}$j$::jsonb,$j${"value": "Ik heb noch tijd noch geld.", "accepted": ["Ik heb noch tijd noch geld.", "Ik heb noch tijd noch geld"]}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$noch_noch_translation$p$, $p$writing$p$]),
('0b59be23-555a-5baf-9f2a-7280c0d3eb5f'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'B2','writing','word_bank',$p$Ordena: 'Aunque estaba cansado, seguí trabajando.' (Recuerda el verbo al final de la subordinada.)$p$,$j${"tiles": ["Hoewel", "ik", "moe", "was", "bleef", "ik", "doorwerken", "ben", "en"]}$j$::jsonb,$j${"value": "Hoewel ik moe was bleef ik doorwerken", "sequence": ["Hoewel", "ik", "moe", "was", "bleef", "ik", "doorwerken"]}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$hoewel_wordbank$p$, $p$writing$p$]),
('d36e5676-e86b-51d6-bd21-84a5805b678f'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'B2','reading','multiple_choice',$p$Concesión con 'hoewel'. Elige la subordinada con el verbo al final.$p$,$j${"options": ["Hoewel het regende, gingen we wandelen.", "Hoewel het hard regende gingen we wandelen.", "Hoewel regende het, gingen we wandelen."]}$j$::jsonb,$j${"value": "Hoewel het regende, gingen we wandelen."}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$hoewel_verb_final$p$, $p$reading$p$]),
