('670d1d99-0514-5820-8b85-4287315ea72f'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,'B2','listening','listening',$p$Escucha y elige la frase exacta.$p$,$j${"options": ["Daarentegen koos hij voor de trein.", "Bovendien koos hij voor de trein.", "Daarentegen koos hij voor de bus."], "say": "Daarentegen koos hij voor de trein.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/670d1d99-0514-5820-8b85-4287315ea72f.mp3"}$j$::jsonb,$j${"value": "Daarentegen koos hij voor de trein."}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$listening_daarentegen$p$, $p$listening$p$]),
