 ('3260c76e-001a-54e9-a48c-b9bb8f95432c','c8ba0703-ee55-5325-8053-f1833da5eb51',3,$p$Nominalización formal: de groei, de toename, het gebruik$p$,$p$Nominalización formal: de groei, de toename, het gebruik$p$,'lesson',15),
 ('20b66b8f-fd66-53f3-9d57-84b90c467b8d','c8ba0703-ee55-5325-8053-f1833da5eb51',4,$p$Practica la nominalización en contexto$p$,$p$Practica la nominalización en contexto$p$,'lesson',15),
 ('97ca51c3-7be7-538b-810e-eb60d5bf521a','c8ba0703-ee55-5325-8053-f1833da5eb51',5,$p$🏁 Checkpoint Eenheid 23$p$,$p$Demuestra que dominas la nominalización del neerlandés B2: el infinitivo sustantivado con «het» (het lezen, bij het koken, door het sporten) y los sustantivos derivados de verbos con su sufijo y artículo correctos (de beslissing, de ontwikkeling, de verklaring, de groei), incluido el registro formal (het gebruik, de toename).$p$,'checkpoint',40)
